import logging

__version__ = '0.3.8'


class DistlibException(Exception):
    pass


try:
    from logging import NoneHandler
except ImportError:  # pragma: no cover

    class NoneHandler(logging.Handler):

        def handle(self, record):
            pass

        def emit(self, record):
            pass

        def createLock(self):
            self.lock = None


logger = logging.getLogger(__name__)
logger.addHandler(NoneHandler())
